import type { Order, HookContext } from "@framework/sdk";

export const onBeforeSave = async (doc: Order, ctx: HookContext) => {
  if (doc.total < 0) throw new Error("Total negatif olamaz");
  doc.totalWithTax = await ctx.tax.calculate(doc.total, doc.taxRegion);
};

export const onSubmit = async (doc: Order, ctx: HookContext) => {
  await ctx.events.publish({ type: "OrderSubmitted", orderId: doc.id });
};
